example.code:
const browser = await puppeteer.launch({
  headless: true,
  args: ['--disable-dev-shm-usage', '--disable-gpu', '--no-sandbox'],
});

let browser;
try {
  browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();
  // ... automation
} catch (e) {
  await page.screenshot({ path: 'failure.png' });
  throw e;
} finally {
  await browser?.close();
}
